#!/usr/bin/env node
// Build the SELF-CONTAINED, transpiler-inclusive browser bundle (#604 / SV80).
//
// Why this exists separately from `build:lib`: the library build (vite, see
// vite.lib.config.ts) is code-split — `dist/index.js` dynamically imports a
// `tree-sitter-*.js` chunk that `npm pack` does NOT ship. So a raw CDN load of
// the published library inits audio but can't transpile ("parser not available").
// esbuild bundles src/engine into ONE file that inlines that chunk, so the
// transpiler comes alive from a single same-origin / CDN import.
//
// What it does NOT bundle:
//   - SuperSonic (GPL scsynth WASM): the engine dynamic-import()s it from the CDN
//     at runtime (a runtime URL string esbuild leaves external).
//   - tree-sitter wasm + the frozen rand-stream wav: fetched from the pinned CDN
//     at runtime via CDN_DEFAULTS. So this bundle is just self-contained JS — a
//     bare consumer needs nothing else on their server.
//
// Output (gitignored — regenerated by `npm run build:browser`, also run by
// `build:lib`):
//   dist/browser.mjs       the self-contained engine bundle
//   dist/browser.mjs.map   its source map
//
// Usage:  node tools/build-browser-bundle.mjs [outfile]
//   or import { buildEngineBundle } from './build-browser-bundle.mjs'

import { build } from 'esbuild'
import { fileURLToPath } from 'node:url'
import { dirname, join } from 'node:path'

const root = join(dirname(fileURLToPath(import.meta.url)), '..')

// web-tree-sitter has dead Node-only branches (`require("fs")`/`require("path")`)
// guarded by environment detection. They never run in the browser; stub them to
// an empty module so esbuild's browser build resolves.
const stubNodeBuiltins = {
  name: 'stub-node-builtins',
  setup(b) {
    b.onResolve({ filter: /^(fs|path|module)$/ }, (a) => ({ path: a.path, namespace: 'stub' }))
    b.onLoad({ filter: /.*/, namespace: 'stub' }, () => ({ contents: 'export default {}', loader: 'js' }))
  },
}

/**
 * Build the self-contained browser bundle.
 * @param {{ outfile: string }} opts
 */
export async function buildEngineBundle({ outfile }) {
  await build({
    entryPoints: [join(root, 'src/engine/index.ts')],
    bundle: true,
    format: 'esm',
    platform: 'browser',
    target: 'es2020',
    sourcemap: true,
    outfile,
    plugins: [stubNodeBuiltins],
    logLevel: 'warning',
  })
}

// Run directly: `node tools/build-browser-bundle.mjs [outfile]`
if (import.meta.url === `file://${process.argv[1]}`) {
  const outfile = process.argv[2] ?? join(root, 'dist', 'browser.mjs')
  await buildEngineBundle({ outfile })
  console.log(`self-contained browser bundle → ${outfile}`)
}
